      ins.forEach(i => insStmt.run(i[0], i[1]));

      console.log('- [Seed] Financial configurations initialized.');
    }
  });

  try {
    tx();
    console.log('[Seed] Database initialization complete.');
  } catch (err) {
    console.error('[Seed] Transaction failed:', err);
  }
};

