const { z } = require('zod');

const validate = (schema) => (req, res, next) => {
  try {
    const parsed = schema.parse(req.body);
    req.body = parsed;
    next();
  } catch (err) {
    return res.status(400).json({ 
      error: 'Validation Error', 
      details: err.errors.map(e => ({ path: e.path.join('.'), message: e.message })) 
    });
  }
};

